import { LemonTag, Tooltip } from '@posthog/lemon-ui'

import { KnowledgeSource } from '../scenes/businessKnowledgeLogic'

export function StatusTag({ source }: { source: KnowledgeSource }): JSX.Element {
    if (source.status === 'ready') {
        // Chunks + keyword (full-text) search are ready immediately, but semantic
        // embeddings are generated by a background job that can take up to an hour.
        if (source.embedding_status === 'pending') {
            return (
                <Tooltip title="Keyword search works already. Semantic search embeddings are generated in the background — this can take up to an hour.">
                    <LemonTag type="completion">indexing</LemonTag>
                </Tooltip>
            )
        }
        return (
            <Tooltip
                title={
                    source.embedding_status === 'disabled'
                        ? 'Indexed for keyword search. Semantic search is off because AI data processing is not approved for your organization.'
                        : 'Fully indexed for keyword and semantic search.'
                }
            >
                <LemonTag type="success">ready</LemonTag>
            </Tooltip>
        )
    }
    const variant = source.status === 'error' ? 'danger' : source.status === 'processing' ? 'warning' : 'muted'
    return <LemonTag type={variant}>{source.status}</LemonTag>
}
